const getRows = (name) => {
  try {
    return $items(name, 0, 0).map((i) => i.json || {});
  } catch (_e) {
    return [];
  }
};

const toStr = (v) => String(v ?? '').trim();
const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};
const norm = (v) => toStr(v)
  .normalize('NFD')
  .replace(/[̀-ͯ]/g, '')
  .toLowerCase();

const form = (getRows('Review Chat Form')[0] || {});
const analysisRows = getRows('Load Impact Analysis');
const repoRows = getRows('Load Repos Table');
const changeRows = getRows('Load Changes In Repo');
const codeRows = getRows('Load Code Changes');
const testsuiteRows = getRows('Load Testsuites For Change');
const testRows = getRows('Load Tests For Testsuite');

if (analysisRows.length === 0) {
  throw new Error('[Build Review Context] data table impact_analysis sem registros.');
}
if (changeRows.length === 0) {
  throw new Error('[Build Review Context] data table changes_in_repo sem registros.');
}
if (codeRows.length === 0) {
  throw new Error('[Build Review Context] data table code_changes sem registros.');
}

const analysisIdInput = toNum(form.analysis_id || form.impact_analysis_id || '');
const allAnalysisIds = analysisRows
  .map((r) => toNum(r.id))
  .filter((n) => Number.isFinite(n));

const selectedAnalysisId = analysisIdInput || (allAnalysisIds.length > 0 ? Math.max(...allAnalysisIds) : null);
if (!selectedAnalysisId) {
  throw new Error('[Build Review Context] nao foi possivel resolver analysis_id.');
}

const analysisRow = analysisRows.find((r) => toNum(r.id) === selectedAnalysisId);
if (!analysisRow) {
  throw new Error('[Build Review Context] analysis_id nao encontrado em impact_analysis: ' + selectedAnalysisId);
}

const repoFilter = norm(form.repo || form.repo_name || '');
const changeIdFilter = toNum(form.change_id || '');
const action = norm(form.acao || form.action || 'ask') === 'request_fix' ? 'request_fix' : 'ask';
const question = toStr(form.pergunta || form.question || form.ask || form.prompt);
if (!question) {
  throw new Error('[Build Review Context] pergunta obrigatoria.');
}

const repoIdToName = new Map();
for (const r of repoRows) {
  const id = toNum(r.id);
  if (!id) continue;
  repoIdToName.set(id, toStr(r.repo_name || r.name || r.slug || 'repo-' + id));
}

const testsBySuite = new Map();
for (const t of testRows) {
  const sid = toNum(t.testsuite_id);
  if (!sid) continue;
  if (!testsBySuite.has(sid)) testsBySuite.set(sid, []);
  const text = toStr(t.description || t.test_description || t.test || t.step);
  if (text) testsBySuite.get(sid).push(text);
}

const suitesByChange = new Map();
for (const s of testsuiteRows) {
  const cid = toNum(s.change_id);
  const sid = toNum(s.id || s.testsuite_id);
  if (!cid || !sid) continue;
  if (!suitesByChange.has(cid)) suitesByChange.set(cid, []);
  suitesByChange.get(cid).push(sid);
}

const codeByChange = new Map();
for (const c of codeRows) {
  const cid = toNum(c.change_id);
  if (!cid) continue;
  if (!codeByChange.has(cid)) codeByChange.set(cid, []);
  const block = toStr(c.code);
  if (block) codeByChange.get(cid).push(block);
}

const assembled = [];
for (const ch of changeRows) {
  const changeId = toNum(ch.id || ch.change_id);
  if (!changeId) continue;

  const repoId = toNum(ch.repo_id);
  const repoName = toStr(ch.repo_name || repoIdToName.get(repoId) || 'repo-' + (repoId || 'na'));
  const summary = toStr(ch.change_summary || ch.summary || ch.descricao || ch.description);

  if (repoFilter && norm(repoName) !== repoFilter) continue;
  if (changeIdFilter && changeId !== changeIdFilter) continue;

  const suiteIds = suitesByChange.get(changeId) || [];
  const tests = suiteIds.flatMap((sid) => testsBySuite.get(sid) || []);
  const codes = (codeByChange.get(changeId) || []).slice(0, 20);

  assembled.push({
    change_id: changeId,
    repo_id: repoId,
    repo_name: repoName,
    change_summary: summary,
    code_changes: codes,
    tests: tests
  });
}

if (assembled.length === 0) {
  throw new Error('[Build Review Context] nenhum change encontrado com os filtros informados.');
}

const payload = {
  analysis_id: selectedAnalysisId,
  analysis_summary: toStr(analysisRow.change_summary || ''),
  analysis_complexity: toStr(analysisRow.complexity_level || ''),
  action,
  question,
  filters: {
    repo: repoFilter || null,
    change_id: changeIdFilter || null
  },
  changes: assembled
};

const reviewContextText = JSON.stringify(payload, null, 2);

return [{
  json: {
    analysis_id: selectedAnalysisId,
    action,
    question,
    review_context_text: reviewContextText,
    review_context_stats: {
      changes: assembled.length,
      code_blocks: assembled.reduce((acc, c) => acc + c.code_changes.length, 0),
      tests: assembled.reduce((acc, c) => acc + c.tests.length, 0),
      chars: reviewContextText.length
    },
    llm_model: toStr(form.llm_model || 'claude-sonnet-4-5-20250929'),
    max_tokens: toNum(form.max_tokens) || 1400,
    anthropic_api_key: toStr(form.anthropic_api_key || '')
  }
}];

const toStr = (v) => String(v ?? '').trim();
const toNum = (v) => {
  const n = Number(v);
  return Number.isFinite(n) ? n : null;
};

const extractText = (resp) => {
  const blocks = Array.isArray(resp?.content) ? resp.content : [];
  return blocks
    .filter((b) => b && b.type === 'text' && typeof b.text === 'string')
    .map((b) => b.text.trim())
    .filter(Boolean)
    .join('
')
    .trim();
};

const tryParseJson = (raw) => {
  try {
    return JSON.parse(raw);
  } catch (_e) {}
  const s = raw.indexOf('{');
  const e = raw.lastIndexOf('}');
  if (s >= 0 && e > s) {
    const cut = raw.slice(s, e + 1);
    try {
      return JSON.parse(cut);
    } catch (_e) {}
  }
  return null;
};

const inJson = $json || {};
const analysisId = toNum(inJson.analysis_id);
if (!analysisId) throw new Error('[Answer Or Request Fix] analysis_id ausente.');

const action = toStr(inJson.action || 'ask');
const question = toStr(inJson.question);
const contextText = toStr(inJson.review_context_text);
if (!question) throw new Error('[Answer Or Request Fix] pergunta ausente.');
if (!contextText) throw new Error('[Answer Or Request Fix] review_context_text ausente.');

const envKey = (typeof process !== 'undefined' && process.env && process.env.ANTHROPIC_API_KEY)
  ? String(process.env.ANTHROPIC_API_KEY).trim()
  : '';
const apiKey = toStr(inJson.anthropic_api_key || envKey);
if (!apiKey) {
  throw new Error('[Answer Or Request Fix] ANTHROPIC_API_KEY ausente no ambiente e no formulario.');
}

const model = toStr(inJson.llm_model || 'claude-sonnet-4-5-20250929');
const maxTokens = toNum(inJson.max_tokens) || 1400;

const systemPrompt = [
  'Voce e revisor tecnico de code changes do FastRoute.',
  'Responda SOMENTE JSON valido, sem markdown.',
  'Use apenas o contexto fornecido.',
  'Formato:',
  '{',
  '  "tipo": "ask|request_fix",',
  '  "resposta": "string",',
  '  "evidencias": ["string"],',
  '  "correcao_sugerida": {',
  '    "change_id": number|null,',
  '    "motivo": "string",',
  '    "novo_codigo": "string"',
  '  }',
  '}',
  'Se nao houver evidencia suficiente, diga claramente no campo resposta.'
].join('
');

const userPrompt = [
  'Pergunta:',
  question,
  '',
  'Acao:',
  action,
  '',
  'Contexto:',
  contextText
].join('
');

let resp;
try {
  resp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: {
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json'
    },
    body: {
      model,
      max_tokens: maxTokens,
      temperature: 0,
      system: systemPrompt,
      messages: [{ role: 'user', content: userPrompt }]
    },
    json: true
  });
} catch (e) {
  const detail = e?.response?.body ? JSON.stringify(e.response.body) : String(e?.message || e);
  throw new Error('[Answer Or Request Fix] erro Anthropic: ' + detail);
}

const raw = extractText(resp);
if (!raw) throw new Error('[Answer Or Request Fix] resposta vazia da Anthropic.');

const parsed = tryParseJson(raw);
if (!parsed || typeof parsed !== 'object') {
  throw new Error('[Answer Or Request Fix] JSON invalido retornado pelo modelo. raw=' + raw.slice(0, 1000));
}

const tipo = toStr(parsed.tipo || action || 'ask');
const resposta = toStr(parsed.resposta);
if (!resposta) throw new Error('[Answer Or Request Fix] campo resposta vazio.');

const evidencias = Array.isArray(parsed.evidencias)
  ? parsed.evidencias.map((x) => toStr(x)).filter(Boolean)
  : [];

const correcao = (parsed.correcao_sugerida && typeof parsed.correcao_sugerida === 'object')
  ? parsed.correcao_sugerida
  : null;

if (tipo === 'request_fix') {
  const ok = correcao && toStr(correcao.motivo) && toStr(correcao.novo_codigo);
  if (!ok) {
    throw new Error('[Answer Or Request Fix] request_fix sem correcao_sugerida completa.');
  }
}

return [{
  json: {
    analysis_id: analysisId,
    action: tipo,
    question,
    resposta,
    evidencias,
    correcao_sugerida: correcao,
    llm_model: model,
    llm_usage: resp?.usage || null,
    llm_stop_reason: toStr(resp?.stop_reason || ''),
    llm_raw_text: raw,
    generated_at: new Date().toISOString()
  }
}];
